#include <stdio.h>
#include <pthread.h>

/* == EXEMPLE ===============================================
 * Race condition avec deux threads sur un tableau
 * Deux threads écrivent dans le même index sans protection.
 * ========================================================= */
int shared_array[10] = {0};

void *writer_example(void *arg) {
    int id = *(int *)arg;
    for (int i = 0; i < 10; i++) {
        shared_array[i] += id;  /* race condition ici */
    }
    return NULL;
}

void example_race(void) {
    pthread_t ta, tb;
    int id_a = 1, id_b = 2;
    pthread_create(&ta, NULL, writer_example, &id_a);
    pthread_create(&tb, NULL, writer_example, &id_b);
    pthread_join(ta, NULL);
    pthread_join(tb, NULL);
    /* Chaque case devrait contenir 3 (1+2) mais pas garanti */
    for (int i = 0; i < 10; i++)
        printf("array[%d]=%d ", i, shared_array[i]);
    printf("\n");
}

